// Check if we've already sent a DM to this commenter on this post
const commentId = $input.item.json.id;
const authorId = $input.item.json.author.id;
const postId = $input.item.json.postId || 'unknown';

// Create a unique key for this comment
const uniqueKey = `${postId}_${authorId}_${commentId}`;

// Use workflow static data to store processed comments
const processedComments = $getWorkflowStaticData('global').processedComments || {};

if (processedComments[uniqueKey]) {
  // Already processed this comment
  return { json: { skip: true, reason: 'Already processed' } };
}

// Mark as processed
processedComments[uniqueKey] = {
  timestamp: new Date().toISOString(),
  processed: true
};

// Clean up old entries (older than 30 days)
const thirtyDaysAgo = Date.now() - (30 * 24 * 60 * 60 * 1000);
for (const key in processedComments) {
  const entryTime = new Date(processedComments[key].timestamp).getTime();
  if (entryTime < thirtyDaysAgo) {
    delete processedComments[key];
  }
}

// Save back to static data
$getWorkflowStaticData('global').processedComments = processedComments;

return { 
  json: { 
    skip: false, 
    ...($input.item.json),
    uniqueKey 
  } 
};

// Analyze comment to determine relevant resource
const commentText = ($input.item.json.text || '').toLowerCase();
const postText = ($input.item.json.postText || '').toLowerCase();

// Keywords for different resource categories
const resourceMap = {
  'ebook': {
    keywords: ['learn', 'guide', 'tutorial', 'how to', 'beginner', 'start', 'ebook', 'book', 'read'],
    resource: {
      title: '📚 Free eBook: Complete Guide to LinkedIn Marketing',
      url: 'https://yourwebsite.com/linkedin-marketing-ebook',
      description: 'A comprehensive guide covering everything from profile optimization to content strategy.'
    }
  },
  'webinar': {
    keywords: ['watch', 'video', 'webinar', 'training', 'course', 'learn more', 'session'],
    resource: {
      title: '🎥 Free Webinar: Advanced LinkedIn Strategies',
      url: 'https://yourwebsite.com/webinar-registration',
      description: 'Join our live webinar to learn advanced tactics from industry experts.'
    }
  },
  'template': {
    keywords: ['template', 'example', 'sample', 'format', 'structure', 'framework'],
    resource: {
      title: '📋 Free Templates: LinkedIn Content Calendar',
      url: 'https://yourwebsite.com/content-templates',
      description: 'Download our proven templates to plan and organize your LinkedIn content.'
    }
  },
  'tool': {
    keywords: ['tool', 'software', 'app', 'automate', 'automation', 'schedule', 'analytics'],
    resource: {
      title: '🛠️ Free Tool: LinkedIn Analytics Dashboard',
      url: 'https://yourwebsite.com/analytics-tool',
      description: 'Track your LinkedIn performance with our free analytics dashboard.'
    }
  },
  'checklist': {
    keywords: ['checklist', 'steps', 'process', 'list', 'tips', 'best practices'],
    resource: {
      title: '✅ Free Checklist: LinkedIn Profile Optimization',
      url: 'https://yourwebsite.com/profile-checklist',
      description: 'A step-by-step checklist to optimize your LinkedIn profile for maximum visibility.'
    }
  }
};

// Determine which resource to send
let selectedResource = null;
let maxMatches = 0;

for (const [category, data] of Object.entries(resourceMap)) {
  let matches = 0;
  for (const keyword of data.keywords) {
    if (commentText.includes(keyword) || postText.includes(keyword)) {
      matches++;
    }
  }

  if (matches > maxMatches) {
    maxMatches = matches;
    selectedResource = data.resource;
  }
}

// Default resource if no specific match
if (!selectedResource) {
  selectedResource = {
    title: '🎁 Free Resource Pack: LinkedIn Success Bundle',
    url: 'https://yourwebsite.com/linkedin-bundle',
    description: 'Get access to our complete resource pack including guides, templates, and tools.'
  };
}

return {
  json: {
    ...($input.item.json),
    selectedResource,
    commenterName: $input.item.json.author?.firstName || 'there'
  }
};

// Create personalized message
const commenterName = $input.item.json.commenterName;
const resource = $input.item.json.selectedResource;

const message = `Hi ${commenterName}! 👋

Thank you so much for engaging with my post! I really appreciate your comment.

I thought you might find this helpful:

${resource.title}
${resource.description}

🔗 Access it here: ${resource.url}

Feel free to reach out if you have any questions. Happy to help! 🚀

Best regards`;

return {
  json: {
    ...($input.item.json),
    messageToSend: message
  }
};

// Log successful send
const timestamp = new Date().toISOString();
const commenterName = $input.item.json.commenterName;
const resourceTitle = $input.item.json.selectedResource.title;

console.log(`✅ SUCCESS: Sent resource "${resourceTitle}" to ${commenterName} at ${timestamp}`);

return {
  json: {
    success: true,
    timestamp,
    commenterName,
    resourceSent: resourceTitle,
    commentId: $input.item.json.id
  }
};
